 53→// FetchPage performs an HTTP GET to fetch a BigFuture college page and returns
 54→// the raw HTML bytes.
 55→func FetchPage(ctx context.Context, client *http.Client, slug string) ([]byte, int, error) {
 56→	url := BigFutureURL(slug)
 57→
 58→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
 59→	if err != nil {
 60→		return nil, 0, fmt.Errorf("deadlines: bigfuture: create request %s: %w", slug, err)
 61→	}
 62→	req.Header.Set("User-Agent", "Kapow/1.0 (+https://github.com/ketang/kapow)")
 63→	req.Header.Set("Accept", "text/html")
 64→
 65→	resp, err := client.Do(req)
 66→	if err != nil {
 67→		return nil, 0, fmt.Errorf("deadlines: bigfuture: fetch %s: %w", slug, err)
 68→	}
 69→	defer resp.Body.Close()
 70→
 71→	body, err := io.ReadAll(resp.Body)
 72→	if err != nil {
 73→		return nil, resp.StatusCode, fmt.Errorf("deadlines: bigfuture: read body %s: %w", slug, err)
 74→	}
 75→
 76→	if resp.StatusCode != http.StatusOK {
 77→		return nil, resp.StatusCode, fmt.Errorf("deadlines: bigfuture: %s returned status %d", slug, resp.StatusCode)
 78→	}
 79→
 80→	return body, resp.StatusCode, nil
