 15→// jsonbObject returns a nested map from data[key], or nil if absent/wrong type.
 16→func jsonbObject(data map[string]any, key string) map[string]any {
 17→	v, ok := data[key]
 18→	if !ok || v == nil {
 19→		return nil
 20→	}
 21→	m, ok := v.(map[string]any)
 22→	if !ok {
 23→		return nil
 24→	}
 25→	return m
 26→}
