// PublicationMeta holds display metadata for a ranking publication+category.
type PublicationMeta struct {
	PublicationSlug string
	Publication     string // display name
	CategorySlug    string
	Category        string // display name
	URL             string
}

// rankingID returns the deterministic key used across ranking tables and the
// institution JSONB column. Format: "pub_slug____cat_slug".
func rankingID(pubSlug, catSlug string) string {
	return pubSlug + "____" + catSlug
}

// RankingBuilder accumulates Opinion values and publication metadata, then
// batch-writes them to the database via Flush.
